private struct TwitchHomeScreen: View {
    var body: some View {
        NavigationStack {
            ZStack(alignment: .bottom) {
                ScrollView {
                    VStack(alignment: .leading, spacing: 20) {
                        TwitchHeroBillboard()
                        ForEach(TwitchDemoData.rows) { row in
                            TwitchPosterRow(title: row.title, items: row.items, accent: TwitchTokens.twitchLiveRed)
                        }
                    }
                    .padding(.bottom, 24)
                }
                .background(TwitchTokens.twitchCanvas.ignoresSafeArea())
            }
            .navigationBarTitleDisplayMode(.inline)
            .toolbar {
                ToolbarItem(placement: .principal) { Text("Twitch").font(.system(size: 20, weight: .bold)).foregroundStyle(TwitchTokens.twitchTextPrimary) }
                ToolbarItem(placement: .topBarTrailing) { Image(systemName: "person.crop.circle").foregroundStyle(TwitchTokens.twitchTextPrimary) }
            }
            .toolbarBackground(TwitchTokens.twitchCanvas, for: .navigationBar)
        }
    }
}

