                Text("Qui regarde ?").font(.system(size: 32, weight: .bold)).foregroundStyle(TwitchTokens.twitchTextPrimary)
                HStack(spacing: 20) {
                    ForEach(profiles) { p in
                        VStack(spacing: 8) {
                            RoundedRectangle(cornerRadius: 4).fill(p.color).frame(width: 84, height: 84)
                                .overlay(Text(p.emoji).font(.system(size: 36)))
                            Text(p.name).foregroundStyle(TwitchTokens.twitchTextSecondary)
                        }
                    }
                    VStack(spacing: 8) {
                        RoundedRectangle(cornerRadius: 4).strokeBorder(TwitchTokens.twitchTextSecondary, lineWidth: 1).frame(width: 84, height: 84)
                            .overlay(Image(systemName: "plus").font(.title).foregroundStyle(TwitchTokens.twitchTextSecondary))
                        Text("Ajouter").foregroundStyle(TwitchTokens.twitchTextSecondary)
                    }
                }
            }
        }
    }
}

